SELECT id, merchant_id, customer_id, payment_id, status, total, currency, notes, created_at, updated_at
FROM orders
WHERE id = #{id}

SELECT * FROM orders


        AND merchant_id = #{merchantId}


        AND customer_id = #{customerId}


        AND payment_id = #{paymentId}


        AND status = #{status}::order_status


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC
